import fs from "fs/promises";
import path from "path";
import { compileMDX } from "next-mdx-remote/rsc";

const BLOG_DIR = path.join(process.cwd(), "contents/blog");

async function findMDXFile(slug: string): Promise<string | null> {
  const years = await fs.readdir(BLOG_DIR);
  for (const year of years) {
    const filePath = path.join(BLOG_DIR, year, `${slug}.mdx`);
    try {
      await fs.access(filePath);
      return filePath;
    } catch {
      continue;
    }
  }
  return null;
}

export default async function Page({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug } = await params;
  const filePath = await findMDXFile(slug);

  if (!filePath) {
    const { notFound } = await import("next/navigation");
    notFound();
  }

  const source = await fs.readFile(filePath, "utf-8");
  const { content, frontmatter } = await compileMDX<{
    title: string;
    date: string;
    description?: string;
  }>({
    source,
    options: { parseFrontmatter: true },
  });

  return (
    <article className="prose prose-invert mx-auto max-w-3xl px-6 py-10">
      <h1>{frontmatter.title}</h1>
      <p className="text-neutral-500">{frontmatter.date}</p>
      {content}
    </article>
  );
}
